const message = $('Telegram Trigger').item.json.message;

let input_text = message.text || message.caption || "";
let message_type = "text";
let has_file = false;
let has_caption = false;
let file_id = null;
let file_name = null;
let mime_type = null;

if (message.voice) {
  message_type = "voice";
  has_file = true;
  file_id = message.voice.file_id;
  mime_type = message.voice.mime_type || "audio/ogg";
  file_name = `voice_${Date.now()}.ogg`;
} else if (message.document) {
  message_type = "document";
  has_file = true;
  file_id = message.document.file_id;
  file_name = message.document.file_name || "unknown_file";
  mime_type = message.document.mime_type || "application/octet-stream";
} else if (message.photo) {
  message_type = "image";
  has_file = true;
  const photos = message.photo;
  file_id = photos[photos.length - 1].file_id;
  mime_type = "image/jpeg";
  file_name = `photo_${Date.now()}.jpg`;
} else if (message.sticker) {
  message_type = "sticker";
} else if (message.video || message.animation || message.contact || message.location || message.video_note) {
  message_type = "unsupported";
}

// Detect commands
let is_command = false;
let command = null;
if (input_text && input_text.startsWith('/')) {
  is_command = true;
  command = input_text.split(' ')[0].split('@')[0].toLowerCase();
}

if (has_file && message_type !== "voice" && message.caption && message.caption.trim().length > 0) {
  has_caption = true;
}

return {
  json: {
    input_text: input_text.trim(),
    message_type,
    has_file,
    has_caption,
    file_id,
    file_name,
    mime_type,
    is_command,
    command,
    user_id: message.from.id,
    user_name: message.chat.first_name || "User",
    chat_id: message.chat.id,
    timestamp: new Date().toISOString()
  }
};

const allItems = $input.all();

const count = allItems.filter(i => i.json._id).length;
const remaining = Math.max(0, 5 - count);
const chatId = $node['Input Preprocessor'].json.chat_id;

return [{
  json: {
    chat_id: chatId,
    count,
    remaining,
    text: `🎤 voice messages today: ${count}/5\n${
      remaining > 0
        ? `you have ${remaining} left!`
        : 'limit reached — resets tomorrow!'
    }`
  }
}];

const tenSecondsAgo = new Date(Date.now() - 10000);
let recentCount = 0;
for (const item of items) {
  const ts = item.json.timestamp ? new Date(item.json.timestamp) : null;
  if (ts && ts >= tenSecondsAgo) recentCount++;
}
const preprocessor = $node["Input Preprocessor"].json;
return [{ json: { ...preprocessor, rate_limited: recentCount >= 5 } }];

const original = $node["Input Preprocessor"].json;
const transcript = $json.text || "";
if (transcript.trim().length < 2) {
  return { json: { ...original, input_text: "", voice_failed: true } };
}
return {
  json: {
    ...original,
    input_text: transcript.trim(),
    message_type: "text",
    has_file: false,
    has_caption: false,
    file_id: null,
    file_name: null,
    mime_type: null,
    voice_transcribed: true
  }
};

const original = $node["Input Preprocessor"].json;
const data = $input.item.json || {};
const extractedText = data.text || "";
const pageCount = data.numpages || 0;
const metadata = data.info || {};
let extraction_note = null;
if (!extractedText || extractedText.trim().length < 10) {
  extraction_note = "[This PDF appears to be scanned/image-based. Text extraction returned minimal content.]";
}
return { json: { ...original, mode: "file", file_type: "pdf", page_count: pageCount, doc_title: metadata.Title || null, doc_author: metadata.Author || null, extracted_text: extraction_note || extractedText, extraction_failed: !!extraction_note } };

const original = $node["Input Preprocessor"].json;
let content = "";
try { const binaryData = $binary.data.data; const buffer = Buffer.from(binaryData, 'base64'); content = buffer.toString('utf8'); } catch (e) { content = "[Failed to read text file]"; }
return { json: { ...original, mode: "file", file_type: "text", extracted_text: content } };

const d = $json;
const instruction = d.input_text || "";
let contentBlock = "";
if (d.file_type === "pdf" || d.file_type === "text") { contentBlock = d.extracted_text || "[No content extracted]"; } else if (d.file_type === "image") { contentBlock = "[Image file — no text content. Use ImageAI to describe if needed.]"; }
const combined = `[User sent a file: ${d.file_name || 'unknown'} (${d.file_type})]\nUser says: "${instruction}"\n\n--- File Content ---\n${contentBlock.substring(0, 8000)}\n---`;
return { json: { ...d, mode: "file", combined_prompt: combined } };

const pending = $json || {};
let currentInput = $node["Input Preprocessor"].json;
let inputText = currentInput.input_text;
try { const voiceData = $node["Voice to Text"].json; if (voiceData && voiceData.input_text && voiceData.voice_transcribed) { inputText = voiceData.input_text; } } catch(e) {}
const hasPending = pending.status === "pending" && pending.file_id;
if (!hasPending) { return { json: { mode: "text", input_text: inputText, combined_prompt: null, file_id: null, file_name: null, file_type: null, mime_type: null, extracted_text: null, user_id: currentInput.user_id, chat_id: currentInput.chat_id, pending_id: null, has_file: false, has_caption: false, message_type: "text" } }; }
const thirtyMinAgo = new Date(Date.now() - 30 * 60 * 1000);
const pendingTime = pending.timestamp ? new Date(pending.timestamp) : null;
const isExpired = !pendingTime || pendingTime < thirtyMinAgo;
if (isExpired) { return { json: { mode: "text", input_text: inputText, combined_prompt: null, file_id: null, file_name: null, file_type: null, mime_type: null, extracted_text: null, user_id: currentInput.user_id, chat_id: currentInput.chat_id, pending_id: pending._id || null, expired_pending: true, has_file: false, has_caption: false, message_type: "text" } }; }
const contentBlock = (pending.extracted_text || "[No content extracted]").substring(0, 8000);
return { json: { mode: "file_followup", input_text: inputText, combined_prompt: `[User has a pending file: ${pending.file_name} (${pending.mime_type})]\nUser now says: "${inputText}"\n\n--- Pending File Content ---\n${contentBlock}\n---`, file_id: pending.file_id, file_name: pending.file_name, file_type: pending.file_type, mime_type: pending.mime_type, extracted_text: pending.extracted_text, user_id: currentInput.user_id, chat_id: currentInput.chat_id, pending_id: pending._id, has_file: true, has_caption: true, message_type: currentInput.message_type || "text" } };

const history = [...items].reverse();
const formatted = [];
for (const item of history) {
  if (item.json.user_input) formatted.push({ role: "user", content: item.json.user_input });
  if (item.json.agent_output) formatted.push({ role: "assistant", content: item.json.agent_output });
}
return [{ json: { conversation_history: formatted } }];

let history = [];
try { history = $node["Format Chat History"].json.conversation_history || []; } catch(e) {}

let memorySnippet = "No memory stored yet.";
try {
  const docContent = $json.body?.content;
  if (docContent && Array.isArray(docContent)) {
    const fullText = docContent.map(block => {
      if (block.paragraph && block.paragraph.elements) {
        return block.paragraph.elements.map(el => el.textRun?.content || "").join("");
      }
      return "";
    }).join("").trim();
    if (fullText.length > 5) memorySnippet = fullText.substring(0, 2000);
  }
} catch(e) { memorySnippet = "Memory unavailable."; }

let currentSource = null;
try { currentSource = $node["Build File Context"].json; } catch(e) {}
if (!currentSource) { try { currentSource = $node["Process Pending"].json; } catch(e) {} }
if (!currentSource) { try { const v = $node["Voice to Text"].json; if (v && v.voice_transcribed) currentSource = v; } catch(e) {} }
if (!currentSource) currentSource = $node["Input Preprocessor"].json;

let currentMessage = currentSource.combined_prompt || currentSource.input_text || "";

const historyText = history.length > 0 ? history.map(m => `${m.role}: ${m.content}`).join('\n\n') : 'No previous conversation.';

return { json: { current_message: currentMessage, history_text: historyText, memory_snippet: memorySnippet, user_id: currentSource.user_id || $node["Input Preprocessor"].json.user_id, chat_id: currentSource.chat_id || $node["Input Preprocessor"].json.chat_id, file_id: currentSource.file_id || null, file_name: currentSource.file_name || null, mime_type: currentSource.mime_type || null, mode: currentSource.mode || "text" } };

const output = $json.output || "";
const preprocessor = $node["Input Preprocessor"].json;
const hasVoiceTag = output.includes("[VOICE]");
const cleanOutput = output.replace(/\[VOICE\]/g, "").trim();
return { json: { ...$json, output: cleanOutput, should_voice: hasVoiceTag, chat_id: preprocessor.chat_id, user_id: preprocessor.user_id } };

const voiceCheck = $node["Voice Check"].json;
const count = items.filter(i => i.json._id).length;
return [{ json: { ...voiceCheck, voice_allowed: count < 5, voice_count: count } }];

const preprocessor = $node["Input Preprocessor"].json;
const voiceCheck = $node["Voice Check"].json;
let userInput = preprocessor.input_text;
try { const v = $node["Voice to Text"].json; if (v && v.voice_transcribed) userInput = v.input_text; } catch(e) {}
return { json: { user_id: preprocessor.user_id, chat_id: preprocessor.chat_id, user_input: userInput || `[Sent ${preprocessor.file_name || preprocessor.message_type}]`, agent_output: voiceCheck.output, message_type: preprocessor.message_type, file_id: preprocessor.file_id || null, voice_response: true, timestamp: new Date().toISOString() } };

const preprocessor = $node["Input Preprocessor"].json;
let userInput = preprocessor.input_text;
try { const v = $node["Voice to Text"].json; if (v && v.voice_transcribed) userInput = v.input_text; } catch(e) {}
let agentOutput = "";
try { agentOutput = $node["Voice Check"].json.output || ""; } catch(e) { agentOutput = $json.output || ""; }
return { json: { user_id: preprocessor.user_id, chat_id: preprocessor.chat_id, user_input: userInput || `[Sent ${preprocessor.file_name || preprocessor.message_type}]`, agent_output: agentOutput, message_type: preprocessor.message_type, file_id: preprocessor.file_id || null, voice_response: false, timestamp: new Date().toISOString() } };
